import{_ as l,o as e,c as a,ag as i}from"./chunks/framework.-Wrcbzkw.js";const g=JSON.parse('{"title":"计算机网络基础","description":"","frontmatter":{},"headers":[],"relativePath":"basic/计算机网络基础/计算机网络基础.md","filePath":"basic/计算机网络基础/计算机网络基础.md","lastUpdated":1778839709000}'),d={name:"basic/计算机网络基础/计算机网络基础.md"};function r(n,t,o,s,h,x){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="计算机网络基础" tabindex="-1">计算机网络基础 <a class="header-anchor" href="#计算机网络基础" aria-label="Permalink to &quot;计算机网络基础&quot;">​</a></h1><h2 id="一、tcp-ip-协议栈" tabindex="-1">一、TCP/IP 协议栈 <a class="header-anchor" href="#一、tcp-ip-协议栈" aria-label="Permalink to &quot;一、TCP/IP 协议栈&quot;">​</a></h2><h3 id="osi-七层模型" tabindex="-1">OSI 七层模型 <a class="header-anchor" href="#osi-七层模型" aria-label="Permalink to &quot;OSI 七层模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">名称</th><th style="text-align:left;">主要功能</th></tr></thead><tbody><tr><td style="text-align:left;">7</td><td style="text-align:left;">应用层</td><td style="text-align:left;">为应用程序提供网络服务（HTTP、FTP、DNS）</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:left;">表示层</td><td style="text-align:left;">数据格式转换、加密解密、压缩解压</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:left;">会话层</td><td style="text-align:left;">建立、管理和终止表示层实体之间的通信会话</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:left;">传输层</td><td style="text-align:left;">端到端的数据传输（TCP、UDP）</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:left;">网络层</td><td style="text-align:left;">路由选择和分组转发（IP）</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;">数据链路层</td><td style="text-align:left;">物理地址寻址、帧同步、差错检测</td></tr><tr><td style="text-align:left;">1</td><td style="text-align:left;">物理层</td><td style="text-align:left;">物理介质上的信号传输</td></tr></tbody></table><h3 id="tcp-ip-四层模型" tabindex="-1">TCP/IP 四层模型 <a class="header-anchor" href="#tcp-ip-四层模型" aria-label="Permalink to &quot;TCP/IP 四层模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">TCP/IP 层</th><th style="text-align:left;">对应 OSI 层</th><th style="text-align:left;">主要协议</th></tr></thead><tbody><tr><td style="text-align:left;">应用层</td><td style="text-align:left;">应用层 + 表示层 + 会话层</td><td style="text-align:left;">HTTP、HTTPS、FTP、SMTP、DNS</td></tr><tr><td style="text-align:left;">传输层</td><td style="text-align:left;">传输层</td><td style="text-align:left;">TCP、UDP</td></tr><tr><td style="text-align:left;">网络层</td><td style="text-align:left;">网络层</td><td style="text-align:left;">IP、ICMP、ARP</td></tr><tr><td style="text-align:left;">网络接口层</td><td style="text-align:left;">数据链路层 + 物理层</td><td style="text-align:left;">以太网、Wi-Fi</td></tr></tbody></table><h2 id="二、ip-协议" tabindex="-1">二、IP 协议 <a class="header-anchor" href="#二、ip-协议" aria-label="Permalink to &quot;二、IP 协议&quot;">​</a></h2><h3 id="ipv4-地址分类" tabindex="-1">IPv4 地址分类 <a class="header-anchor" href="#ipv4-地址分类" aria-label="Permalink to &quot;IPv4 地址分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">范围</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">A</td><td style="text-align:left;">1.0.0.0 - 126.255.255.255</td><td style="text-align:left;">大型网络</td></tr><tr><td style="text-align:left;">B</td><td style="text-align:left;">128.0.0.0 - 191.255.255.255</td><td style="text-align:left;">中型网络</td></tr><tr><td style="text-align:left;">C</td><td style="text-align:left;">192.0.0.0 - 223.255.255.255</td><td style="text-align:left;">小型网络</td></tr><tr><td style="text-align:left;">D</td><td style="text-align:left;">224.0.0.0 - 239.255.255.255</td><td style="text-align:left;">多播</td></tr></tbody></table><h3 id="私有-ip-地址" tabindex="-1">私有 IP 地址 <a class="header-anchor" href="#私有-ip-地址" aria-label="Permalink to &quot;私有 IP 地址&quot;">​</a></h3><ul><li>A 类：<code>10.0.0.0 - 10.255.255.255</code></li><li>B 类：<code>172.16.0.0 - 172.31.255.255</code></li><li>C 类：<code>192.168.0.0 - 192.168.255.255</code></li></ul><h2 id="三、tcp-协议" tabindex="-1">三、TCP 协议 <a class="header-anchor" href="#三、tcp-协议" aria-label="Permalink to &quot;三、TCP 协议&quot;">​</a></h2><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li>面向连接：建立连接 → 数据传输 → 断开连接</li><li>可靠传输：确认、重传、流量控制、拥塞控制</li><li>有序交付：按顺序传递数据</li></ul><h3 id="三次握手" tabindex="-1">三次握手 <a class="header-anchor" href="#三次握手" aria-label="Permalink to &quot;三次握手&quot;">​</a></h3><ol><li>客户端 → 服务器：SYN</li><li>服务器 → 客户端：SYN + ACK</li><li>客户端 → 服务器：ACK</li></ol><h3 id="四次挥手" tabindex="-1">四次挥手 <a class="header-anchor" href="#四次挥手" aria-label="Permalink to &quot;四次挥手&quot;">​</a></h3><ol><li>客户端 → 服务器：FIN</li><li>服务器 → 客户端：ACK</li><li>服务器 → 客户端：FIN</li><li>客户端 → 服务器：ACK</li></ol><h2 id="四、udp-协议" tabindex="-1">四、UDP 协议 <a class="header-anchor" href="#四、udp-协议" aria-label="Permalink to &quot;四、UDP 协议&quot;">​</a></h2><h3 id="特点-1" tabindex="-1">特点 <a class="header-anchor" href="#特点-1" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li>无连接：不需要建立连接</li><li>不可靠传输：不保证数据到达，不保证顺序</li><li>面向报文：保留消息边界</li><li>开销小：头部只有 8 字节</li></ul><h3 id="udp-vs-tcp" tabindex="-1">UDP vs TCP <a class="header-anchor" href="#udp-vs-tcp" aria-label="Permalink to &quot;UDP vs TCP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">TCP</th><th style="text-align:left;">UDP</th></tr></thead><tbody><tr><td style="text-align:left;">连接</td><td style="text-align:left;">面向连接</td><td style="text-align:left;">无连接</td></tr><tr><td style="text-align:left;">可靠性</td><td style="text-align:left;">可靠</td><td style="text-align:left;">不可靠</td></tr><tr><td style="text-align:left;">速度</td><td style="text-align:left;">较慢</td><td style="text-align:left;">较快</td></tr><tr><td style="text-align:left;">开销</td><td style="text-align:left;">20-60 字节</td><td style="text-align:left;">8 字节</td></tr></tbody></table><h2 id="五、http-https" tabindex="-1">五、HTTP/HTTPS <a class="header-anchor" href="#五、http-https" aria-label="Permalink to &quot;五、HTTP/HTTPS&quot;">​</a></h2><h3 id="http-方法" tabindex="-1">HTTP 方法 <a class="header-anchor" href="#http-方法" aria-label="Permalink to &quot;HTTP 方法&quot;">​</a></h3><ul><li>GET：获取资源</li><li>POST：提交数据</li><li>PUT：更新资源</li><li>DELETE：删除资源</li><li>HEAD：获取头部</li><li>OPTIONS：获取支持的方法</li></ul><h3 id="状态码" tabindex="-1">状态码 <a class="header-anchor" href="#状态码" aria-label="Permalink to &quot;状态码&quot;">​</a></h3><ul><li>1xx：信息性</li><li>2xx：成功（200 OK）</li><li>3xx：重定向（301 永久重定向）</li><li>4xx：客户端错误（404 Not Found）</li><li>5xx：服务器错误（500 Internal Error）</li></ul><h3 id="请求头-响应头" tabindex="-1">请求头/响应头 <a class="header-anchor" href="#请求头-响应头" aria-label="Permalink to &quot;请求头/响应头&quot;">​</a></h3><ul><li>Content-Type、Content-Length</li><li>Cookie、Set-Cookie</li><li>Authorization</li></ul><h3 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-label="Permalink to &quot;HTTPS&quot;">​</a></h3><ul><li>加密方式：非对称加密 + 对称加密</li><li>端口：默认 443</li></ul><h2 id="六、cookie-session-token" tabindex="-1">六、Cookie / Session / Token <a class="header-anchor" href="#六、cookie-session-token" aria-label="Permalink to &quot;六、Cookie / Session / Token&quot;">​</a></h2><ul><li><strong>Cookie</strong>：存储在客户端的文本信息</li><li><strong>Session</strong>：服务端存储的会话信息</li><li><strong>Token</strong>：无状态的令牌（如 JWT）</li></ul><h2 id="七、dns-与跨域" tabindex="-1">七、DNS 与跨域 <a class="header-anchor" href="#七、dns-与跨域" aria-label="Permalink to &quot;七、DNS 与跨域&quot;">​</a></h2><ul><li><strong>DNS</strong>：域名解析为 IP 地址</li><li><strong>跨域</strong>：浏览器同源策略限制，CORS 是解决方案</li></ul><h2 id="八、网络基础概念" tabindex="-1">八、网络基础概念 <a class="header-anchor" href="#八、网络基础概念" aria-label="Permalink to &quot;八、网络基础概念&quot;">​</a></h2><h3 id="url-特殊符号" tabindex="-1">URL 特殊符号 <a class="header-anchor" href="#url-特殊符号" aria-label="Permalink to &quot;URL 特殊符号&quot;">​</a></h3><ul><li><code>#</code>：位置标识符，改变不重新加载</li><li><code>?</code>：连接作用，参数开始</li><li><code>&amp;</code>：不同参数的分隔符</li></ul><h3 id="常用协议" tabindex="-1">常用协议 <a class="header-anchor" href="#常用协议" aria-label="Permalink to &quot;常用协议&quot;">​</a></h3><ul><li><strong>ARP</strong>：IP 地址转换为 MAC 地址</li><li><strong>ICMP</strong>：控制消息和错误报告（ping）</li><li><strong>DHCP</strong>：自动分配 IP 地址</li></ul>',41)])])}const c=l(d,[["render",r]]);export{g as __pageData,c as default};
